   211	    boolean matchesPattern(Map<String, Object> event, String eventPattern) {
   212	        if (eventPattern == null || eventPattern.isBlank()) {
   213	            return true;
   214	        }
   215	        try {
   216	            JsonNode pattern = objectMapper.readTree(eventPattern);
   217	            JsonNode sourceField = pattern.get("source");
   218	            if (sourceField != null && sourceField.isArray()) {
   219	                String eventSource = (String) event.get("Source");
   220	                if (!matchesArrayField(sourceField, eventSource)) {
   221	                    return false;
   222	                }
   223	            }
   224	            JsonNode detailTypeField = pattern.get("detail-type");
   225	            if (detailTypeField != null && detailTypeField.isArray()) {
   226	                String eventDetailType = (String) event.get("DetailType");
   227	                if (!matchesArrayField(detailTypeField, eventDetailType)) {
   228	                    return false;
   229	                }
   230	            }
   231	            JsonNode detailPattern = pattern.get("detail");
   232	            if (detailPattern != null && detailPattern.isObject()) {
   233	                Object eventDetail = event.get("Detail");
   234	                String detailStr = eventDetail instanceof String s ? s : null;
   235	                if (detailStr == null) {
   236	                    return false;
   237	                }
   238	                JsonNode detailNode = objectMapper.readTree(detailStr);
   239	                var fields = detailPattern.fields();
   240	                while (fields.hasNext()) {
   241	                    var field = fields.next();
   242	                    JsonNode expected = field.getValue();
   243	                    JsonNode actual = detailNode.get(field.getKey());
   244	                    String actualStr = actual != null ? actual.asText(null) : null;
   245	                    if (expected.isArray() && !matchesArrayField(expected, actualStr)) {
   246	                        return false;
   247	                    }
   248	                }
   249	            }
   250	            return true;
   251	        } catch (Exception e) {
   252	            LOG.warnv("Failed to parse event pattern: {0}", e.getMessage());
   253	            return false;
   254	        }
   255	    }
