   257	    private boolean matchesArrayField(JsonNode arrayNode, String value) {
   258	        if (value == null) return false;
   259	        for (JsonNode element : arrayNode) {
   260	            if (value.equals(element.asText())) {
   261	                return true;
   262	            }
   263	        }
   264	        return false;
   265	    }
