   269	    private void invokeTarget(Target target, String eventJson, String region) {
   270	        String arn = target.getArn();
   271	        String payload = target.getInput() != null ? target.getInput() : eventJson;
   272	        try {
   273	            if (arn.contains(":lambda:") || arn.contains(":function:")) {
   274	                String fnName = arn.substring(arn.lastIndexOf(':') + 1);
   275	                String fnRegion = extractRegionFromArn(arn, region);
   276	                lambdaService.invoke(fnRegion, fnName, payload.getBytes(), InvocationType.Event);
   277	                LOG.debugv("EventBridge delivered to Lambda: {0}", arn);
   278	            } else if (arn.contains(":sqs:")) {
   279	                String queueUrl = sqsArnToUrl(arn);
   280	                sqsService.sendMessage(queueUrl, payload, 0);
   281	                LOG.debugv("EventBridge delivered to SQS: {0}", arn);
   282	            } else if (arn.contains(":sns:")) {
   283	                String topicRegion = extractRegionFromArn(arn, region);
   284	                snsService.publish(arn, null, payload, "EventBridge", topicRegion);
   285	                LOG.debugv("EventBridge delivered to SNS: {0}", arn);
   286	            } else {
   287	                LOG.warnv("EventBridge: unsupported target ARN type: {0}", arn);
   288	            }
   289	        } catch (Exception e) {
   290	            LOG.warnv("EventBridge failed to deliver to target {0}: {1}", arn, e.getMessage());
   291	        }
   292	    }
