   294	    private String buildEventEnvelope(Map<String, Object> entry, String busName, String eventId) {
   295	        try {
   296	            String source = (String) entry.getOrDefault("Source", "");
   297	            String detailType = (String) entry.getOrDefault("DetailType", "");
   298	            String detail = (String) entry.getOrDefault("Detail", "{}");
   299	            ObjectNode node = objectMapper.createObjectNode();
   300	            node.put("version", "0");
   301	            node.put("id", eventId);
   302	            node.put("source", source);
   303	            node.put("detail-type", detailType);
   304	            node.put("account", regionResolver.getAccountId());
   305	            node.put("time", Instant.now().toString());
   306	            node.put("region", regionResolver.getDefaultRegion());
   307	            node.putArray("resources");
   308	            node.set("detail", objectMapper.readTree(detail));
   309	            node.put("event-bus-name", busName);
   310	            return objectMapper.writeValueAsString(node);
   311	        } catch (Exception e) {
   312	            return "{}";
   313	        }
   314	    }
